const incoming = $input.first().json ?? {};
return [{
  json: {
    triggerSource: 'webhook',
    triggerLabel: 'Deploy webhook',
    deploymentId: incoming.deployment_id ?? incoming.deploy_id ?? incoming.deployment?.id ?? incoming.sha ?? null,
    deploymentMeta: {
      branch: incoming.branch ?? incoming.ref ?? null,
      sha: incoming.sha ?? incoming.commit ?? null,
      status: incoming.status ?? incoming.state ?? null,
      raw: incoming
    }
  }
}];

const sourceItem = $input.first()?.json ?? {};
const triggerSource = sourceItem.triggerSource ?? 'manual';
const triggerLabel = sourceItem.triggerLabel ?? (triggerSource === 'webhook' ? 'Deploy webhook' : 'Manual run');
const deploymentMeta = sourceItem.deploymentMeta ?? {};
const targets = [
  { name: 'homepage', url: 'https://gimenez.dev/', expectJsonStatus: false },
  { name: 'health_api', url: 'https://gimenez.dev/api/health', expectJsonStatus: true },
  { name: 'war_room', url: 'https://gimenez.dev/war-room', expectJsonStatus: false },
  { name: 'war_room_data', url: 'https://gimenez.dev/api/war-room/data', expectJsonStatus: false },
  { name: 'chat_page', url: 'https://gimenez.dev/chat', expectJsonStatus: false }
];

return targets.map((target, index) => ({
  json: {
    ...target,
    triggerSource,
    triggerLabel,
    deploymentMeta,
    checkId: index + 1,
    workflow: 'deploy-guardian'
  }
}));

const workflowStaticData = $getWorkflowStaticData('global');
const checkedAt = new Date().toISOString();
const inputItems = $input.all();
const sourceItem = inputItems.find((item) => item.json.triggerSource) ?? inputItems[0] ?? {};
const triggerSource = sourceItem.json?.triggerSource ?? 'manual';
const triggerLabel = sourceItem.json?.triggerLabel ?? (triggerSource === 'webhook' ? 'Deploy webhook' : 'Manual run');
const deploymentMeta = sourceItem.json?.deploymentMeta ?? {};

const results = inputItems.map((item) => {
  const target = {
    name: item.json.name ?? `unknown-${item.pairedItem?.item ?? 0}`,
    url: item.json.url ?? null,
    expectJsonStatus: item.json.expectJsonStatus ?? false
  };
  const bodyText = String(item.json.body ?? '');
  let appStatus = null;

  if (target.expectJsonStatus) {
    try {
      const parsed = JSON.parse(bodyText);
      appStatus = parsed.status ?? null;
    } catch (error) {
      appStatus = bodyText ? 'invalid-json' : null;
    }
  }

  const statusCode = Number(item.json.statusCode ?? 0);
  const healthy = !item.json.error && statusCode >= 200 && statusCode < 400 && (!target.expectJsonStatus || appStatus === 'healthy');

  return {
    name: target.name,
    url: target.url,
    healthy,
    statusCode: statusCode || null,
    statusMessage: item.json.statusMessage ?? null,
    appStatus,
    error: item.json.error ?? null,
    proxyLatencyMs: item.json.duration ?? null,
    checksum: target.expectJsonStatus ? appStatus : null
  };
});

const failures = results.filter((result) => !result.healthy);
const previousFailures = Number(workflowStaticData.deployGuardianFailures || 0);
const consecutiveFailures = failures.length > 0 ? previousFailures + 1 : 0;
const shouldEscalate = failures.length > 0 && consecutiveFailures >= 2;

workflowStaticData.deployGuardianFailures = consecutiveFailures;
workflowStaticData.lastDeployGuardianCheck = checkedAt;
workflowStaticData.lastDeployStatus = failures.length > 0 ? (shouldEscalate ? 'incident' : 'degraded') : 'healthy';

const summary = failures.length > 0
  ? `${failures.length} failing smoke checks: ${failures.map((result) => result.name).join(', ')}`
  : 'all smoke checks successful';

return [
  {
    json: {
      workflow: 'deploy-guardian',
      checkedAt,
      triggerSource,
      triggerLabel,
      deploymentMeta,
      status: failures.length > 0 ? (shouldEscalate ? 'incident' : 'degraded') : 'healthy',
      shouldEscalate,
      consecutiveFailures,
      summary,
      results
    }
  }
];

const payload = $input.first().json;
const failingChecks = (payload.results || []).filter((check) => !check.healthy).map((check) => check.name);
const icon = payload.status === 'healthy'
  ? ':white_check_mark:'
  : payload.status === 'degraded'
    ? ':warning:'
    : ':rotating_light:';
const lines = [
  `${icon} *Deploy Guardian* ${String(payload.status || 'unknown').toUpperCase()}`,
  `Run: ${payload.triggerLabel || payload.triggerSource || 'manual'}`,
  `Checked: ${payload.checkedAt}`,
  `Summary: ${payload.summary}`
];
if (payload.deploymentMeta?.sha) {
  lines.push(`SHA: ${payload.deploymentMeta.sha}`);
}
if (failingChecks.length > 0) {
  lines.push(`Failing checks: ${failingChecks.join(', ')}`);
}
return [
  {
    json: {
      ...payload,
      slackNotification: {
        skip: false,
        channel: 'C0ALX8C12TG',
        text: lines.join('\n')
      }
    }
  }
];

const payload = $input.first().json;
if (!payload.shouldEscalate) {
  return [{ json: { ...payload, escalated: false } }];
}
const failing = payload.results?.filter((check) => !check.healthy) ?? [];
throw new Error(JSON.stringify({
  workflow: payload.workflow,
  status: payload.status,
  summary: payload.summary,
  consecutiveFailures: payload.consecutiveFailures,
  deploymentMeta: payload.deploymentMeta,
  failingChecks: failing
}));
